var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"시체의 피가 전부 사라졌어.","JPN":"死体の血が全部消えてる。","ENG":"The corpse is completely drained of blood.","TWN":"屍體的血全都消失了。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"죽은 지 오래된 시체는 아닌 것 같은데…….","JPN":"死んでからあまり時間は経ってなさそうだが……","ENG":"Doesn't seem like it's been dead for long...","TWN":"看起來不是死了很久的屍體……"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"형제님?","JPN":"ブラザー？","ENG":"Brother Ludwig?","TWN":"弟兄？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"……끊어졌군.","JPN":"……切れてる。","ENG":"...The connection's cut off.","TWN":"……掛斷了。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"젠장. 지금이라도 돌아갈까?","JPN":"くそ。今からでも帰るか？","ENG":"Damn it. Should I turn back now?","TWN":"可惡。要不現在回去？"},"stage":{"bg":"HALL","slots":{"L":null,"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L11_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"하지만, 이 시체는 그냥 넘어갈 수 없겠는데.","JPN":"でも、死体をこのまま放っておけないしな。","ENG":"But I can't just ignore this body.","TWN":"但是，這具屍體不能輕易忽略。"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"합의체의 키메라? 챔버가 합의체의 연구를 도와준다는 소문은 들었는데.","JPN":"合意体のキメラ？　チェンバーが合意体の研究を援助しているって噂は聞いたけど。","ENG":"A chimera from the Northern Union? I've heard rumors that Chamber was helping with their research.","TWN":"和議會的奇美拉？聽說和議會的研究得到了強巴的幫助。"},"stage":{"bg":"HALL","slots":{"L":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"그렇다고 해도…… 왜 그게 대부호의 저택에 있냐고.","JPN":"そうだとしても……どうしてそれが大富豪の邸宅にいるわけ？","ENG":"But even if that's true... why is it in a noble's mansion?","TWN":"即便如此……為什麼那會在大富翁的屋子裡呢。"},"stage":{"bg":"HALL","slots":{"L":null,"C":null,"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"필요할때만 날 찾는구나.","JPN":"必要な時しか呼んでくれないのね。","ENG":"You only call me when you need something.","TWN":"你只有在需要的時候才會找我。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"내가 그렇게 버릇없게 키운 적은 없었던 것 같은데.","JPN":"私、そんなに礼儀知らずな子に育てた覚えはないけれど。","ENG":"Pretty sure I didn't raise you to be so rude.","TWN":"我好像從來沒有把你教得這麼沒規矩。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"키우긴 뭘 키워요. 사진이나 엄청나게 찍어댔지.","JPN":"育ててないでしょう。写真を撮りまくってただけじゃないですか。","ENG":"Raise me? More like spent all your time taking pictures of me.","TWN":"教什麼教，只是拍了很多照片而已。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"여기서 한 번 <color=#ffd34c>광증</color>이 발현됐어요.","JPN":"それはそうと、さっき<color=#ffd34c>狂症</color>が発現しました。","ENG":"There was a case of the <color=#ffd34c>madness</color> here.","TWN":"在這裡，我的<color=#ffd34c>狂症</color>發作了一次。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"광증? 네가?","JPN":"狂症？　あなたが？","ENG":"Madness? Are you talking about yourself?","TWN":"狂症？你？"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"어쩌면 만월이라 그럴 가능성도 있겠어.","JPN":"満月だからって可能性もあるわね。","ENG":"Maybe it's because of the full moon... That would make sense.","TWN":"也許是因為月圓的緣故吧。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"하지만…… 좀 예민해지기만 할 뿐 이런 적은 없었는데.","JPN":"でも……今まではちょっと敏感になるだけだったのに。","ENG":"But... it usually just makes you a little on edge. You've never lost control like this before.","TWN":"但是……只是變得有些敏感而已，之前從未有過這樣的情況。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"갑자기 이러니까 좀 이상하더라고요.","JPN":"いきなりああなるなんて、ちょっとおかしいです。","ENG":"Yeah. It felt strange.","TWN":"突然這樣做，有點奇怪呢。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"<color=#ffd34c>10년 전 그날</color>에도 멀쩡했던 제가…….","JPN":"<color=#ffd34c>10年前のあの日</color>にも何ともなかった私が……","ENG":"Even <color=#ffd34c>ten years ago</color> on that night, I stayed completely sane.","TWN":"<color=#ffd34c>10年前的那天</color>我也安然無恙。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"순식간에 이성을 잃었다는게.","JPN":"一瞬で理性を失うなんて。","ENG":"But now, all of a sudden, I snap?","TWN":"瞬間就失去了理智。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"다시 그런 증상이 나타나기 전에 서두르자.","JPN":"またその症状が出る前に急ぎましょう。","ENG":"Let's wrap this up before it happens again.","TWN":"在再次出現那種症狀之前趕緊行動吧。"},"stage":{"bg":"HALL","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"수녀는 찾았어?","JPN":"シスターは見つかった？","ENG":"Did you find the nun?","TWN":"找到修女了嗎？"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"여기에도 수녀는 없네요.","JPN":"ここにもシスターはいませんね。","ENG":"She's nowhere to be found.","TWN":"這裡也沒有修女呢。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"피 냄새는 계속해서 이어지고 있는데…….","JPN":"血の匂いはずっと続いてるのに……","ENG":"But the smell of blood keeps lingering...","TWN":"血腥味還在彌漫……"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"어떡하면 좋을지 모르겠어요.","JPN":"ちょっと行き詰まりって感じです。","ENG":"I don't know what to do.","TWN":"我不知道該怎麼辦才好。"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"AGNES_MOONLIGHT_NULL_NULL","text":{"KOREA":"돈이 걸린 문제가 아니라서 그런가?","JPN":"お金がかかった問題じゃないからかしら？","ENG":"Is it because there's no money on the line?","TWN":"因為不是涉及到錢的問題嗎？"},"stage":{"bg":"CORRIDOR_06","slots":{"L":null,"C":{"char_id":"AGNES_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};